"\"\"\"Agent Browser \u2014 Session Pool + Form/Login Engine (Crawlee \u9a71\u52a8)\n\n\u57fa\u4e8e Crawlee \u7684 SessionPool\uff1a\n- \u81ea\u52a8 Cookie/Session \u7ba1\u7406\n- \u667a\u80fd\u767b\u5f55\n- \u8868\u5355\u586b\u5145\n\"\"\"\nfrom typing import Optional, Dict, Any, List\nfrom dataclasses import dataclass, field\nimport logging\n\nlogger = logging.getLogger(\"agent-browser.sessions\")\n\n@dataclass\nclass LoginResult:\n    url: str\n    success: bool = False\n    session_id: str = \"\"\n    cookies_count: int = 0\n    error: str = \"\"\n    elapsed_ms: float = 0\n\n@dataclass\nclass FormResult:\n    url: str\n    form_id: str = \"\"\n    fields_filled: Dict[str, str] = field(default_factory=dict)\n    submitted: bool = False\n    response_text: str = \"\"\n    error: str = \"\"\n    elapsed_ms: float = 0\n\nclass SessionPoolEngine:\n    \"\"\"Crawlee SessionPool \u5c01\u88c5\"\"\"\n\n    def __init__(self):\n        self._pool = None\n\n    async def _get_pool(self):\n        if self._pool is None:\n            from crawlee.sessions import SessionPool\n            self._pool = SessionPool(\n                max_pool_size=10,\n                create_session_settings={\"max_age_secs\": 3600}\n            )\n        return self._pool\n\n    async def login(self, login_url: str, username: str, password: str) -> LoginResult:\n        import time\n        start = time.time()\n        result = LoginResult(url=login_url)\n\n        try:\n            from crawlee import PlaywrightCrawler\n            from crawlee.playwright_crawler import PlaywrightCrawlingContext\n            from crawlee.sessions import SessionPool\n\n            pool = SessionPool(max_pool_size=1)\n            session = await pool.get_session()\n\n            crawler = PlaywrightCrawler(\n                max_requests_per_crawl=1,\n                headless=True,\n                session_pool=pool,\n            )\n\n            login_done = False\n\n            @crawler.request_handler\n            async def handler(context: PlaywrightCrawlingContext) -> None:\n                nonlocal login_done\n                page = context.page\n                await page.goto(login_url, wait_until=\"networkidle\", timeout=30000)\n                await page.wait_for_timeout(1500)\n\n                # \u68c0\u6d4b\u7528\u6237\u540d/\u5bc6\u7801\u5b57\u6bb5\n                username_field = await page.evaluate(\"\"\"() => {\n                    for (const el of document.querySelectorAll('input')) {\n                        const n = (el.name || '').toLowerCase();\n                        if (['username','user','email','login','account'].some(x => n.includes(x))) {\n                            return el.name || el.id;\n                        }\n                    }\n                    return '';\n                }\"\"\")\n                pwd_field = await page.query_selector(\"input[type='password']\")\n\n                if username_field and pwd_field:\n                    await page.fill(f\"[name='{username_field}']\", username)\n                    pwd_name = await pwd_field.get_attribute(\"name\") or \"\"\n                    await page.fill(f\"[name='{pwd_name}']\", password)\n                    try:\n                        await page.click(\"button[type='submit'], input[type='submit']\")\n                    except:\n                        await page.evaluate(\"document.forms[0].submit()\")\n                    await page.wait_for_load_state(\"networkidle\", timeout=10000)\n                    login_done = True\n\n            await crawler.run([login_url])\n\n            if login_done:\n                result.success = True\n                result.session_id = session.id if session else \"\"\n                cookies = await crawler._browser_plugin.browser.contexts[0].cookies() if hasattr(crawler, '_browser_plugin') else []\n                result.cookies_count = len(cookies)\n            else:\n                result.error = \"No login form detected\"\n\n            await crawler.close()\n        except Exception as e:\n            result.error = f\"Crawlee login failed: {str(e)[:300]}\"\n            logger.error(f\"Login error: {e}\")\n\n            # Fallback\n            try:\n                from services.login import LoginEngine\n                from services.renderer import get_renderer\n                renderer = await get_renderer()\n                engine = LoginEngine()\n                legacy_result = await engine.login(renderer, login_url, username, password)\n                result.success = legacy_result.success\n                result.session_id = legacy_result.session_id\n                result.cookies_count = legacy_result.cookies_count\n            except Exception as e2:\n                result.error += f\" | Legacy fallback: {str(e2)[:100]}\"\n\n        result.elapsed_ms = (time.time() - start) * 1000\n        return result\n"